/** Per-board configuration (one entry in `groups`). */
export type PulseBoardBoardConfig = {
  /** Require the bot to be @-mentioned before replying. Defaults to true. */
  requireMention?: boolean;
  tools?: GroupToolPolicyConfig;
  enabled?: boolean;
  /** Additional allowFrom list scoped to this board. */
  allowFrom?: Array<string | number>;
  systemPrompt?: string;
};

/** Account-level PulseBoard configuration. */
export type PulseBoardAccountConfig = {
  name?: string;
  enabled?: boolean;
  /** PulseBoard server host (e.g. boards.example.com). */
  host?: string;
  /** HTTPS port for the PulseBoard API. Defaults to 443. */
  port?: number;
  /** Use TLS for the connection. Defaults to true. */
  tls?: boolean;
  /** The bot's PulseBoard username. */
  username?: string;
  /** API key for the bot account. */
  apiKey?: string;
  /** Path to a file containing the API key (read at startup). */
  apiKeyFile?: string;
  /** DM access control policy. Defaults to "pairing". */
  dmPolicy?: DmPolicy;
  allowFrom?: Array<string | number>;
  /** Board access control policy. Defaults to "allowlist". */
  groupPolicy?: GroupPolicy;
  /** allowFrom applied to all boards when no board-specific list is set. */
