// PulseBoard target and allowlist normalization helpers.
//
// Board targets use a "!" prefix (e.g. "!general", "!announcements").
// User targets are plain lowercase usernames or qualified "user@host" forms.

/** Returns true when the target refers to a board (group) rather than a user. */
export function isBoardTarget(target: string): boolean {
  return target.startsWith("!");
}

const PULSEBOARD_SIMPLE_ID_PATTERN = /^[a-z0-9_\-@.]+$/u;

/**
 * Normalize a raw messaging target string to a canonical PulseBoard target.
 *
 * Accepts the following input forms:
 *   - "pulseboard:!general"  → "!general"
 *   - "board:general"        → "!general"
 *   - "user:alice"           → "alice"
 *   - "!general"             → "!general"
 *   - "alice"                → "alice"
 *
 * Returns undefined when the input is not a recognizable target.
 */
export function normalizePulseBoardMessagingTarget(raw: string): string | undefined {
  const trimmed = raw.trim();
  if (!trimmed) {
    return undefined;
  }

  let target = trimmed;

  // Strip channel-prefix alias "pulseboard:".
  const lower = target.toLowerCase();
  if (lower.startsWith("pulseboard:")) {
    target = target.slice("pulseboard:".length).trim();
  }

  // "board:<name>" shorthand → "!<name>".
  if (target.toLowerCase().startsWith("board:")) {
    target = target.slice("board:".length).trim();
    if (!target.startsWith("!")) {
      target = `!${target}`;
    }
  }

  // "user:<username>" shorthand.
  if (target.toLowerCase().startsWith("user:")) {
    target = target.slice("user:".length).trim();
  }

  if (!target || !looksLikePulseBoardTargetId(target)) {
    return undefined;
  }

  // Usernames are always stored in lowercase; board names preserve their case.
  return isBoardTarget(target) ? target : target.toLowerCase();
}

/** Returns true when the string looks like a valid PulseBoard target ID. */
export function looksLikePulseBoardTargetId(raw: string): boolean {
  const trimmed = raw.trim();
  if (!trimmed) {
    return false;
  }
  // Board targets: "!" followed by one or more word characters.
  if (trimmed.startsWith("!")) {
    return PULSEBOARD_SIMPLE_ID_PATTERN.test(trimmed.slice(1));
  }
  return PULSEBOARD_SIMPLE_ID_PATTERN.test(trimmed);
}

/**
 * Normalize a single allowFrom entry to a canonical lowercase string.
 * Returns an empty string when the input is invalid.
 */
export function normalizePulseBoardAllowEntry(raw: string): string {
  let value = raw.trim().toLowerCase();
  if (!value) {
    return "";
  }
  if (value.startsWith("pulseboard:")) {
    value = value.slice("pulseboard:".length);
  }
  if (value.startsWith("user:")) {
    value = value.slice("user:".length);
  }
  return value.trim();
}

/** Normalize an array of allowFrom entries, filtering out invalid ones. */
export function normalizePulseBoardAllowlist(entries?: Array<string | number>): string[] {
  return (entries ?? []).map((entry) => normalizePulseBoardAllowEntry(String(entry))).filter(Boolean);
}

/**
 * Check whether a sender username matches any entry in an allowlist.
 * Supports the wildcard "*".
 */
export function resolvePulseBoardAllowlistMatch(params: {
  allowFrom: string[];
  senderUsername: string;
}): { allowed: boolean; source?: string } {
  const normalized = normalizePulseBoardAllowlist(params.allowFrom);
  const allowSet = new Set(normalized);
  if (allowSet.has("*")) {
    return { allowed: true, source: "wildcard" };
  }
  const sender = params.senderUsername.trim().toLowerCase();
  if (allowSet.has(sender)) {
    return { allowed: true, source: sender };
  }
  return { allowed: false };
}

