input.content:
import {
  normalizePulseBoardAllowlist,
  resolvePulseBoardAllowlistMatch,
} from "./normalize.js";
import type { PulseBoardAccountConfig, PulseBoardBoardConfig } from "./types.js";

export type PulseBoardGroupMatch = {
  allowed: boolean;
  boardConfig?: PulseBoardBoardConfig;
  wildcardConfig?: PulseBoardBoardConfig;
  hasConfiguredGroups: boolean;
};

export type PulseBoardGroupAccessGate = {
  allowed: boolean;
  reason: string;
};

/**
 * Match an inbound board target against the configured groups map.
 * Board targets are compared case-insensitively.
 */
export function resolvePulseBoardGroupMatch(params: {
  groups?: Record<string, PulseBoardBoardConfig>;
  target: string;
}): PulseBoardGroupMatch {
  const groups = params.groups ?? {};
  const hasConfiguredGroups = Object.keys(groups).length > 0;

  // Direct case-sensitive lookup first.
  const direct = groups[params.target];
  if (direct) {
    return {
      allowed: true,
      boardConfig: direct,
      wildcardConfig: groups["*"],
      hasConfiguredGroups,
    };
  }

  // Case-insensitive fallback (board names may differ in capitalization).
  const targetLower = params.target.toLowerCase();
  const directKey = Object.keys(groups).find((key) => key.toLowerCase() === targetLower);
  if (directKey) {
    const matched = groups[directKey];
    if (matched) {
      return {
        allowed: true,
        boardConfig: matched,
        wildcardConfig: groups["*"],
        hasConfiguredGroups,
      };
    }
  }

  // Wildcard fallback.
  const wildcard = groups["*"];
  if (wildcard) {
    return {
      allowed: true,
      wildcardConfig: wildcard,
      hasConfiguredGroups,
    };
  }

  return { allowed: false, hasConfiguredGroups };
}

/** Evaluate board access given the configured groupPolicy and the match result. */
export function resolvePulseBoardGroupAccessGate(params: {
  groupPolicy: PulseBoardAccountConfig["groupPolicy"];
  groupMatch: PulseBoardGroupMatch;
}): PulseBoardGroupAccessGate {
  const policy = params.groupPolicy ?? "allowlist";

  if (policy === "disabled") {
    return { allowed: false, reason: "groupPolicy=disabled" };
  }

  if (policy === "allowlist") {
    if (!params.groupMatch.hasConfiguredGroups) {
      return { allowed: false, reason: "groupPolicy=allowlist and no boards configured" };
    }
    if (!params.groupMatch.allowed) {
      return { allowed: false, reason: "not allowlisted" };
    }
  }

  // Explicit per-board or wildcard disable wins regardless of policy.
  if (
    params.groupMatch.boardConfig?.enabled === false ||
    params.groupMatch.wildcardConfig?.enabled === false
  ) {
    return { allowed: false, reason: "disabled" };
  }

  return { allowed: true, reason: policy === "open" ? "open" : "allowlisted" };
}

/** Resolve whether the bot must be @-mentioned before replying on a board. */
export function resolvePulseBoardRequireMention(params: {
  boardConfig?: PulseBoardBoardConfig;
  wildcardConfig?: PulseBoardBoardConfig;
}): boolean {
  if (params.boardConfig?.requireMention !== undefined) {
    return params.boardConfig.requireMention;
  }
  if (params.wildcardConfig?.requireMention !== undefined) {
    return params.wildcardConfig.requireMention;
  }
  // Default: require mention in boards.
  return true;
}

/** Resolve whether a sender is allowed in a board given the layered allowlists. */
export function resolvePulseBoardGroupSenderAllowed(params: {
  groupPolicy: PulseBoardAccountConfig["groupPolicy"];
  senderUsername: string;
  outerAllowFrom: string[];
  innerAllowFrom: string[];
}): boolean {
  const policy = params.groupPolicy ?? "allowlist";
  const inner = normalizePulseBoardAllowlist(params.innerAllowFrom);
  const outer = normalizePulseBoardAllowlist(params.outerAllowFrom);

  // Board-level allowlist takes precedence over the account-level list.
  if (inner.length > 0) {
    return resolvePulseBoardAllowlistMatch({
      allowFrom: inner,
      senderUsername: params.senderUsername,
    }).allowed;
  }
  if (outer.length > 0) {
    return resolvePulseBoardAllowlistMatch({
      allowFrom: outer,
      senderUsername: params.senderUsername,
    }).allowed;
  }
  return policy === "open";
}

