import { resolvePulseBoardAccount } from "./accounts.js";
import { normalizePulseBoardMessagingTarget } from "./normalize.js";
import { getPulseBoardRuntime } from "./runtime.js";
import type { CoreConfig } from "./types.js";

export type SendPulseBoardResult = {
  messageId: string;
  target: string;
};

type SendPulseBoardOptions = {
  cfg?: CoreConfig;
  accountId?: string;
  replyTo?: string;
};

function recordPulseBoardOutboundActivity(accountId: string): void {
  try {
    getPulseBoardRuntime().channel.activity.record({
      channel: "pulseboard",
      accountId,
      direction: "outbound",
    });
  } catch (error) {
    // Swallow "runtime not initialized" errors that can happen during setup;
    // any other error is re-thrown.
    if (!(error instanceof Error) || error.message !== "PulseBoard runtime not initialized") {
      throw error;
    }
  }
}

function resolveTarget(to: string): string {
  const normalized = normalizePulseBoardMessagingTarget(to);
  if (!normalized) {
    throw new Error(`Invalid PulseBoard target: ${to}`);
  }
  return normalized;
}

/**
 * Send a text message to a PulseBoard board or user.
 *
 * In a real implementation this would POST to the PulseBoard HTTP API:
 *   - Board message: POST /v1/boards/{boardId}/messages
 *   - Direct message: POST /v1/users/{username}/messages
 *
 * The call is made using the resolved account's API key as a Bearer token.
 * For this plugin skeleton the HTTP call is represented as a documented stub
 * so the rest of the plugin wiring can be tested without a live server.
 */
export async function sendMessagePulseBoard(
  to: string,
  text: string,
  opts: SendPulseBoardOptions = {},
): Promise<SendPulseBoardResult> {
  const runtime = getPulseBoardRuntime();
  const cfg = (opts.cfg ?? runtime.config.loadConfig()) as CoreConfig;
  const account = resolvePulseBoardAccount({ cfg, accountId: opts.accountId });

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" ` +
        "(need host, username, and apiKey in channels.pulseboard).",
    );
  }

  const target = resolveTarget(to);
  const payload = opts.replyTo ? `${text.trim()}\n\n[reply:${opts.replyTo}]` : text.trim();

  if (!payload) {
    throw new Error("Message must be non-empty for PulseBoard sends");
  }

  const baseUrl = `${account.tls ? "https" : "http"}://${account.host}:${account.port}`;
  const isBoardMsg = target.startsWith("!");
  const endpoint = isBoardMsg
    ? `${baseUrl}/v1/boards/${encodeURIComponent(target.slice(1))}/messages`
    : `${baseUrl}/v1/users/${encodeURIComponent(target)}/messages`;

  // Send via the PulseBoard HTTP API.
  const response = await fetch(endpoint, {
    method: "POST",
    headers: {
      Authorization: `Bearer ${account.apiKey}`,
      "Content-Type": "application/json",
    },
    body: JSON.stringify({ text: payload }),
  });

  if (!response.ok) {
    const body = await response.text().catch(() => "");
    throw new Error(
      `PulseBoard API error ${response.status} for account "${account.accountId}": ${body}`,
    );
  }

  const json = (await response.json()) as { messageId?: string };
  const messageId = json.messageId ?? `pb-${Date.now()}`;

  recordPulseBoardOutboundActivity(account.accountId);

  return { messageId, target };
}

