import { describe, expect, it } from "vitest";
import { resolvePulseBoardAccount, listPulseBoardAccountIds } from "./accounts.js";
import type { CoreConfig } from "./types.js";

function makeCfg(
  overrides: Partial<NonNullable<CoreConfig["channels"]>["pulseboard"]> = {},
): CoreConfig {
  return {
    channels: {
      pulseboard: {
        host: "boards.example.com",
        username: "testbot",
        apiKey: "pb_test_key",
        ...overrides,
      },
    },
  } as CoreConfig;
}

describe("resolvePulseBoardAccount", () => {
  it("resolves a configured account", () => {
    const cfg = makeCfg();
    const account = resolvePulseBoardAccount({ cfg });
    expect(account.configured).toBe(true);
    expect(account.host).toBe("boards.example.com");
    expect(account.username).toBe("testbot");
    expect(account.apiKey).toBe("pb_test_key");
  });

  it("returns configured=false when host is missing", () => {
    const cfg = makeCfg({ host: undefined });
    const account = resolvePulseBoardAccount({ cfg });
    expect(account.configured).toBe(false);
    expect(account.host).toBe("");
  });

  it("returns configured=false when username is missing", () => {
    const cfg = makeCfg({ username: undefined });
    const account = resolvePulseBoardAccount({ cfg });
    expect(account.configured).toBe(false);
  });

  it("returns configured=false when apiKey is missing", () => {
    const cfg = makeCfg({ apiKey: undefined });
    const account = resolvePulseBoardAccount({ cfg });
    expect(account.configured).toBe(false);
    expect(account.apiKeySource).toBe("none");
  });

  it("defaults tls to true", () => {
    const cfg = makeCfg();
    const account = resolvePulseBoardAccount({ cfg });
    expect(account.tls).toBe(true);
    expect(account.port).toBe(443);
  });

  it("sets port to 80 when tls is false", () => {
    const cfg = makeCfg({ tls: false });
    const account = resolvePulseBoardAccount({ cfg });
    expect(account.tls).toBe(false);
    expect(account.port).toBe(80);
  });

  it("respects a custom port", () => {
    const cfg = makeCfg({ port: 8443 });
    const account = resolvePulseBoardAccount({ cfg });
    expect(account.port).toBe(8443);
  });

  it("returns enabled=false when top-level enabled is false", () => {
    const cfg = makeCfg({ enabled: false });
    const account = resolvePulseBoardAccount({ cfg });
    expect(account.enabled).toBe(false);
  });

  it("resolves apiKey from config", () => {
    const cfg = makeCfg({ apiKey: "pb_from_config" });
    const account = resolvePulseBoardAccount({ cfg });
    expect(account.apiKey).toBe("pb_from_config");
    expect(account.apiKeySource).toBe("config");
  });
});

describe("listPulseBoardAccountIds", () => {
  it("returns the default account when configured", () => {
    const cfg = makeCfg();
    const ids = listPulseBoardAccountIds(cfg);
    expect(ids).toContain("default");
  });

  it("returns an empty list when pulseboard is not configured", () => {
    const cfg = {} as CoreConfig;
    const ids = listPulseBoardAccountIds(cfg);
    expect(ids).toHaveLength(0);
  });
});

